// 재전송 본문 파싱: 원 제목·원 발신자·사안 식별자 추출
// 재전송으로 헤더(threadId/References) 파괴됨 → 본문 기반 매칭이 주력
const body = $input.item.json.text || $input.item.json.snippet || '';
const subject = $input.item.json.subject || '';

// 원 제목 추출 (Fwd: / FW: 제거, 인용 헤더에서 Subject: 추출)
const fwdClean = subject.replace(/^(Fwd?:\s*)+/i, '').trim();
const quotedSubject = body.match(/^Subject:\s*(.+)$/mi)?.[1]?.trim();
const originalSubject = quotedSubject || fwdClean;

// 원 발신자 추출 (인용 헤더 From: 패턴)
const originalFrom = body.match(/^From:\s*(.+)$/mi)?.[1]?.trim() || '';

// 사안 식별자 추출 (WP-번호, 접수번호 패턴)
const wpRef = body.match(/\bWP-\d+\b/)?.[0] || null;
const caseRef = body.match(/\b(접수|사안|case)[-_\s]?\d+\b/i)?.[0] || null;

// 규제기관 판별
const regions = [
  { keywords: ['FDA', '510(k)', '510k', 'De Novo', 'CDRH', 'QMSR', '21 CFR'], region: 'US', actor: 'ra_us' },
  { keywords: ['MDR', 'CE mark', 'IVDR', 'Notified Body', 'EUDAMED', 'CER', '2017/745'], region: 'EU', actor: 'ra_eu' },
  { keywords: ['MFDS', 'KGMP', '식품의약품안전처', '의료기기', 'KFDA', '허가', '신고'], region: 'KR', actor: 'ra_kr' }
];

const searchText = (originalSubject + ' ' + body).toLowerCase();
let matched = [];
for (const r of regions) {
  if (r.keywords.some(k => searchText.includes(k.toLowerCase()))) {
    matched.push(r);
  }
}

const matchingKey = [
  originalSubject.toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_가-힣]/g, '').slice(0, 60),
  originalFrom.split('@')[0]?.replace(/[^a-z0-9가-힣]/g, '') || '',
  wpRef || caseRef || ''
].filter(Boolean).join('|');

return [{
  json: {
    raw_subject: subject,
    original_subject: originalSubject,
    original_from: originalFrom,
    wp_ref: wpRef,
    case_ref: caseRef,
    matching_key: matchingKey,
    body_excerpt: body.slice(0, 500),
    matched_regions: matched,
    routing_status: matched.length === 1 ? 'green' : matched.length === 0 ? 'yellow_no_region' : 'yellow_multi_region',
    primary_actor: matched.length === 1 ? matched[0].actor : null,
    primary_region: matched.length === 1 ? matched[0].region : null,
    email_id: $input.item.json.id,
    received_at: new Date().toISOString()
  }
}];

// RA 분석 결과 JSON 파싱 및 검증
// 고정 계약: { actor, wp, match, confidence, region, comment, transition_proposed }
const raw = $input.item.json;
let analysis;
try {
  const content = raw.choices?.[0]?.message?.content || raw.content || '{}';
  // JSON 블록 추출 (모델이 마크다운으로 감쌀 수 있음)
  const jsonMatch = content.match(/```json\s*([\s\S]+?)\s*```/) || content.match(/({[\s\S]+})/);
  analysis = JSON.parse(jsonMatch ? jsonMatch[1] : content);
} catch (e) {
  return [{ json: { parse_error: true, raw_content: raw.choices?.[0]?.message?.content || '', error: e.message } }];
}

// 필수 필드 검증
const required = ['actor', 'match', 'confidence', 'region', 'comment'];
const missing = required.filter(f => analysis[f] === undefined);
if (missing.length > 0) {
  return [{ json: { parse_error: true, missing_fields: missing, analysis } }];
}

return [{ json: { ...analysis, parse_error: false } }];

// Honcho conclusion 기록: 사안↔WP 매핑
// 활동 기록 계약 형식 (고정)
const analysis = $json;
const parsed = $node['본문 파싱 및 규제권 라우팅'].json;

const activityRecord = {
  ts: new Date().toISOString(),
  type: analysis.match === 'existing' ? 'matched' : 'matched',
  actor: analysis.actor,
  payload: {
    wp: analysis.wp,
    match: analysis.match,
    confidence: analysis.confidence,
    region: analysis.region,
    matching_key: parsed.matching_key,
    original_subject: parsed.original_subject,
    email_id: parsed.email_id
  }
};

const mailRecord = {
  ts: parsed.received_at,
  type: 'mail_received',
  actor: 'system',
  payload: {
    region: analysis.region,
    subject: parsed.original_subject,
    email_id: parsed.email_id,
    target: analysis.actor
  }
};

return [{ json: { activity_record: activityRecord, mail_record: mailRecord, analysis } }];

