// Yellow 게이트: 규제권 미판별 또는 다중 판별
// 사람에게 알림 전송 (이메일 또는 OpenProject 코멘트)
const parsed = $input.item.json;
const reason = parsed.routing_status === 'yellow_no_region'
  ? '규제기관 미판별 — 수동 배정 필요'
  : '복수 규제권 감지(' + parsed.matched_regions.map(r => r.region).join(', ') + ') — 담당 지정 필요';

return [{
  json: {
    alert_type: 'yellow_routing',
    reason,
    original_subject: parsed.original_subject,
    original_from: parsed.original_from,
    matching_key: parsed.matching_key,
    body_excerpt: parsed.body_excerpt,
    email_id: parsed.email_id
  }
}];
